function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    let maxScore = -1;

    function dfs(node, currentCost, minEdgeCost) {
        if (node === n - 1) {
            if (currentCost <= k) {
                maxScore = Math.max(maxScore, minEdgeCost);
            }
            return;
        }
        for (const [neighbor, cost] of adj[node]) {
            if (online[neighbor]) {
                const newCost = currentCost + cost;
                if (newCost > k) continue;
                const newMin = Math.min(minEdgeCost, cost);
                dfs(neighbor, newCost, newMin);
            }
        }
    }

    dfs(0, 0, Infinity);
    return maxScore === -1 ? -1 : maxScore;
}

