import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<long[]>> adj = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            adj.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = edge[2];
            adj.get(u).add(new long[]{v, cost});
        }

        long[] maxMinCost = new long[n];
        Arrays.fill(maxMinCost, -1);
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(b[1], a[1]));
        pq.offer(new long[]{0, Long.MAX_VALUE, 0});

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int node = (int) current[0];
            long currentMin = current[1];
            long currentCost = current[2];

            if (node == n - 1) {
                if (currentCost <= k) {
                    return currentMin;
                }
                continue;
            }

            if (maxMinCost[node] >= currentMin) {
                continue;
            }
            maxMinCost[node] = currentMin;

            for (long[] neighborInfo : adj.get(node)) {
                int neighbor = (int) neighborInfo[0];
                long cost = neighborInfo[1];
                if (online[neighbor]) {
                    long newCost = currentCost + cost;
                    if (newCost > k) {
                        continue;
                    }
                    long newMin = Math.min(currentMin, cost);
                    if (newMin > maxMinCost[neighbor]) {
                        pq.offer(new long[]{neighbor, newMin, newCost});
                    }
                }
            }
        }

        return -1;
    }
}
